import { Hono } from 'hono';
import { z } from 'zod';
import nodemailer from 'nodemailer';

const app = new Hono();

// Mock database for demonstration purposes
let users: any[] = [];
let sessions: any[] = [];

// Mock user data
users.push({ id: 1, email: 'admin@example.com', role: 'admin' });
users.push({ id: 2, email: 'user@example.com', role: 'member' });

// Mock session data
sessions.push({ userId: 1, token: 'admin-session-token' });

const InviteSchema = z.object({
  email: z.string().email(),
});

app.post('/invite-member', async (c) => {
  const authHeader = c.req.headers.get('Authorization');
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'Unauthorized' }, 401);
  }

  const token = authHeader.split(' ')[1];
  const session = sessions.find(s => s.token === token);

  if (!session) {
    return c.json({ error: 'Unauthorized' }, 401);
  }

  const user = users.find(u => u.id === session.userId);
  if (user.role !== 'admin') {
    return c.json({ error: 'Unauthorized' }, 403);
  }

  const { email } = await InviteSchema.parseAsync(await c.req.json());

  // Generate a single-use invite token
  const inviteToken = Math.random().toString(36).substring(2, 15);

  // Email the invite token to the invitee
  const transporter = nodemailer.createTransport({
    service: 'gmail',
    auth: {
      user: 'your-email@gmail.com', // Replace with your email
      pass: 'your-password', // Replace with your password
    },
  });

  await transporter.sendMail({
    from: 'your-email@gmail.com', // Replace with your email
    to: email,
    subject: 'Invitation to Join Our Community',
    text: `You have been invited to join our community. Please use the following token to register: ${inviteToken}`,
  });

  // Add the invitee immediately if a valid session exists (for demonstration purposes)
  const newUser = { id: users.length + 1, email, role: 'member' };
  users.push(newUser);

  return c.json({ message: 'Invite sent successfully', token: inviteToken });
});

export default app;

